class ListNode {
  val: number;
  next: ListNode | null;
  constructor(val: number = 0, next: ListNode | null = null) {
    this.val = val;
    this.next = next;
  }
}

function mergeKLists(lists: Array<ListNode | null>): ListNode | null {
  if (!lists || lists.length === 0) {
    return null;
  }

  // Min heap using a simple comparison approach
  const minHeap: ListNode[] = [];

  // Add first node from each list to heap
  for (const list of lists) {
    if (list !== null) {
      minHeap.push(list);
    }
  }

  // Sort to maintain heap property
  minHeap.sort((a, b) => a.val - b.val);

  const dummy = new ListNode(0);
  let current = dummy;

  while (minHeap.length > 0) {
    // Get node with minimum value
    minHeap.sort((a, b) => a.val - b.val);
    const minNode = minHeap.shift()!;

    // Add to result
    current.next = minNode;
    current = current.next;

    // Add next node from same list if exists
    if (minNode.next !== null) {
      minHeap.push(minNode.next);
    }
  }

  return dummy.next;
}
